                            newItemName = ""
                            viewModel.showExplorerCreateDialog = false
                        }
                    }) {
                        Text("Create")
                    }
                },
                dismissButton = {
                    TextButton(onClick = { viewModel.showExplorerCreateDialog = false; newItemName = "" }) {
                        Text("Cancel")
                    }
                }
            )
        }

        // Floating Options Bar
        androidx.compose.animation.AnimatedVisibility(
